+#[cfg(feature = "async")]
+impl AsyncCmd {
+    /// Create a new async command from an async closure.
+    pub fn new<F, Fut>(f: F) -> Self
+    where
+        F: FnOnce() -> Fut + Send + 'static,
+        Fut: Future<Output = Message> + Send + 'static,
+    {
