+where
+    F: Fn(&AuthContext, &str) -> std::pin::Pin<Box<dyn std::future::Future<Output = bool> + Send>>
+        + Send
+        + Sync,
+{
+    /// Creates a new async callback-based auth handler.
+    #[allow(dead_code)]
+    pub fn new(callback: Arc<F>) -> Self {
+        Self { callback }
+    }
+}
+
+#[async_trait]
