+            debug!(username = %ctx.username(), "AsyncCallbackAuth: password accepted");
+            AuthResult::Accept
+        } else {
+            debug!(username = %ctx.username(), "AsyncCallbackAuth: password rejected");
+            AuthResult::Reject
+        }
+    }
+
+    fn supported_methods(&self) -> Vec<AuthMethod> {
+        vec![AuthMethod::Password]
+    }
